from agent import *from models.products import *XCAT = ["Főoldal"]def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=10000)]    session.queue(Request('https://sg.hu/', use="curl"), process_frontpage, dict())def process_frontpage(data, context, session):    cats = data.xpath('//div[@id="footer-top"]/a')    for cat in cats:        name = cat.xpath("text()").string()        url = cat.xpath("@href").string()        if url and name and name not in XCAT:            session.queue(Request(url, use="curl"), process_revlist, dict(cat=name, url=url))def process_revlist(data, context, session):    prods = data.xpath("//div[contains(@class, 'article-block')]")    for prod in prods:        name = prod.xpath("h4/text()").string()        if name == context.get("first_rev_name"):            return        if not context.get("first_rev_name"):            context["first_rev_name"] = name        url = prod.xpath("a/@href").string()        if "?page=" not in url:            session.queue(Request(url, use="curl"), process_review, dict(context, name=name, url=url))    page = context.get("page", 1) + 1    url = context["url"] + "?page=" + str(page)    session.queue(Request(url, use="curl"), process_revlist, dict(context, page=page))def process_review(data, context, session):    product = Product()    product.name = context["name"]    product.url = context["url"]    product.ssid = product.url.split('/')[-2]    product.category = context["cat"]    imgs = data.xpath("(//div[@id='content']/img[contains(@src, '.jpg')] | //div[@id='article-body']//img[contains(@src, '.jpg')])/@src")    for img in imgs:        img = img.string()        product.properties.append(ProductProperty(type='image', value=dict(src=img, type='product')))    review = Review()    review.type = "pro"    review.title = product.name    review.ssid = product.ssid    review.url = product.url    date = data.xpath('//meta[@property="article:published_time"]/@content').string()    if date:        review.date = date.split('T')[0]    author = data.xpath("//div[@id='article-info']/p/text()").string()    if author:        review.authors.append(Person(name=author, ssid=author))    excerpt = data.xpath("//div[@id='article-body']//text()").string(multiple=True)    if excerpt:        review.add_property(type="excerpt", value=excerpt)        product.reviews.append(review)        session.emit(product)